#include <stdio.h>
#include <string.h> // Required for strlen, strcspn
#include <ctype.h>  // Required for isalpha, isupper, islower

#define MAX_LINE_LENGTH 1001 // Max 1000 characters + null terminator

int main() {
    char line[MAX_LINE_LENGTH];
    int shift;

    // Read the input string from stdin
    // fgets is used to read an entire line, including spaces, up to MAX_LINE_LENGTH-1 characters.
    // It also reads the newline character if present.
    if (fgets(line, sizeof(line), stdin) == NULL) {
        // Handle potential input error
        return 1;
    }

    // Remove the trailing newline character that fgets might include
    // strcspn finds the first occurrence of a character from the second string in the first string.
    // Here, it finds the newline and replaces it with a null terminator.
    line[strcspn(line, "\n")] = 0;

    // Read the integer shift value from stdin
    if (scanf("%d", &shift) != 1) {
        // Handle potential input error
        return 1;
    }

    // Iterate through each character in the string
    for (int i = 0; line[i] != '\0'; i++) {
        char current_char = line[i];

        // Check if the character is an alphabet letter
        if (isalpha(current_char)) {
            char base; // 'A' for uppercase, 'a' for lowercase
            if (isupper(current_char)) {
                base = 'A';
            } else { // islower(current_char)
                base = 'a';
            }

            // Calculate the 0-25 offset of the current character from its base ('A' or 'a')
            int offset = current_char - base;

            // Apply the shift. The modulo operator (%) in C can return negative results for
            // negative dividends. Adding 26 before the final modulo ensures a positive result
            // that correctly wraps around the 0-25 range for both positive and negative shifts.
            offset = (offset + (shift % 26) + 26) % 26;

            // Convert the new offset back to a character and update the string
            line[i] = base + offset;
        }
        // Non-alphabetic characters are left unchanged
    }

    // Print the encoded string followed by a newline
    printf("%s\n", line);

    return 0;
}
